import { Injectable, signal, computed } from '@angular/core';
import { Router } from '@angular/router';
import { inject } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { Observable } from 'rxjs';
import { tap } from 'rxjs';

export interface AdminUser {
  id: string;
  email: string;
  name: string;
  role: 'admin';
}

/** Shape of `POST /api/auth/login` on success. */
interface LoginResponse {
  token: string;
  user: { id: string; email: string; name: string | null; role: string };
}

const STORAGE_KEYS = {
  token: 'token',
  accessToken: 'access_token',
  user: 'user',
  isAuthenticated: 'isAuthenticated',
};

/**
 * Auth service for the admin-only access model.
 *
 * The visualization page (`/`) is fully public. Only the `(admin)` route
 * group (job inspection + settings) is protected. In the mockup there is no
 * real backend, so `login()` and `demoLogin()` set mock admin credentials in
 * localStorage and flip an authentication signal.
 */
@Injectable({ providedIn: 'root' })
export class AuthService {
  private readonly router = inject(Router);
  private readonly http = inject(HttpClient);

  private readonly authState = signal<boolean>(this.readPersistedAuth());
  private readonly currentUser = signal<AdminUser | null>(this.readPersistedUser());

  readonly isAuthenticated = computed(() => this.authState());
  readonly user = computed(() => this.currentUser());

  private readPersistedAuth(): boolean {
    try {
      return localStorage.getItem(STORAGE_KEYS.isAuthenticated) === 'true';
    } catch {
      return false;
    }
  }

  private readPersistedUser(): AdminUser | null {
    try {
      const raw = localStorage.getItem(STORAGE_KEYS.user);
      return raw ? (JSON.parse(raw) as AdminUser) : null;
    } catch {
      return null;
    }
  }

  private persist(user: AdminUser, token: string): void {
    try {
      localStorage.setItem(STORAGE_KEYS.token, token);
      localStorage.setItem(STORAGE_KEYS.accessToken, token);
      localStorage.setItem(STORAGE_KEYS.user, JSON.stringify(user));
      localStorage.setItem(STORAGE_KEYS.isAuthenticated, 'true');
    } catch {
      /* storage unavailable — auth still held in-memory via signals */
    }
  }

  /**
   * Admin credential login against the NestJS auth API. On success the issued
   * JWT is persisted (the interceptor attaches it to admin-only requests) and
   * the admin is routed to the console. Errors propagate so the login form can
   * show "Invalid email or password".
   */
  login(email: string, password: string): Observable<LoginResponse> {
    return this.http
      .post<LoginResponse>('/api/auth/login', { email, password })
      .pipe(
        tap((res) => {
          const user: AdminUser = {
            id: res.user.id,
            email: res.user.email,
            name: res.user.name ?? res.user.email,
            role: 'admin',
          };
          this.persist(user, res.token);
          this.currentUser.set(user);
          this.authState.set(true);
          this.router.navigate(['/admin/jobs']);
        }),
      );
  }

  /**
   * Demo Mode bypass — flips the client-side auth signal so the admin console
   * is reachable without credentials. Admin-only API calls still require a real
   * JWT, so live data only populates after a genuine sign-in.
   */
  demoLogin(): void {
    const user: AdminUser = {
      id: 'admin-demo',
      email: 'demo.admin@noaa-viz.local',
      name: 'Demo Admin',
      role: 'admin',
    };
    this.persist(user, 'demo-mode');
    this.currentUser.set(user);
    this.authState.set(true);
    this.router.navigate(['/admin/jobs']);
  }

  logout(): void {
    try {
      Object.values(STORAGE_KEYS).forEach((k) => localStorage.removeItem(k));
    } catch {
      /* ignore */
    }
    this.currentUser.set(null);
    this.authState.set(false);
    this.router.navigate(['/admin/login']);
  }
}
